const LOGO_B64 = "data:image/png;base64,";
let currentStep=0,totalSteps=4,selections={},fotos=[],fotoCount=0;

document.addEventListener('DOMContentLoaded',()=>{
  document.getElementById('data-lev').valueAsDate=new Date();
  document.getElementById('revisao').value='R0';
  loadCodigosSuggestions();
  verificarRascunho(); addFoto(); updateNav();
});

function goToStep(i){ autoSave(); if(i===currentStep)return; if(i===totalSteps-1)buildSummary(); currentStep=i; document.querySelectorAll('.section').forEach(s=>s.classList.remove('active')); document.getElementById(`section-${i}`).classList.add('active'); updateNav(); updateTabs(); window.scrollTo(0,0); }
function goNext(){ if(currentStep===totalSteps-1){generateDocument();return;} goToStep(currentStep+1); }
function goBack(){ if(currentStep>0)goToStep(currentStep-1); }
function updateNav(){
  document.getElementById('btn-back').style.display=currentStep>0&&currentStep<totalSteps?'':'none';
  const btn=document.getElementById('btn-next'),nav=document.getElementById('nav-bar');
  if(currentStep===totalSteps){nav.style.display='none';return;}
  nav.style.display='flex';
  if(currentStep===totalSteps-1){btn.textContent='✓ Gerar Documento';btn.className='btn btn-generate';}
  else{btn.textContent='Continuar →';btn.className='btn btn-next';}
}
function updateTabs(){
  for(let i=0;i<totalSteps;i++){const t=document.getElementById(`tab-${i}`);if(!t)continue;t.className='step-tab';if(i===currentStep)t.classList.add('active');else if(i<currentStep)t.classList.add('done');}
}
function escHtml(s){ return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;'); }
function loadCodigosSuggestions(){ const _raw=localStorage.getItem('fercayo_codigos'); const _obj=_raw?JSON.parse(_raw):{data:[]}; const s=Array.isArray(_obj)?_obj:(_obj.data||[]); document.getElementById('codigos-list').innerHTML=s.map(c=>`<option value="${escHtml(c)}">` ).join(''); }
function saveCodigoSuggestion(v){
  if(!v||v.length<2)return;
  const raw=localStorage.getItem('fercayo_codigos');
  let obj=raw?JSON.parse(raw):{ts:Date.now(),data:[]};
  // limpar se tiver mais de 90 dias
  if(!obj.ts||Date.now()-obj.ts>90*24*60*60*1000){obj={ts:Date.now(),data:[]};}
  const s=obj.data;
  if(!s.includes(v)){s.unshift(v);if(s.length>20)s.pop();}
  obj.ts=Date.now();
  localStorage.setItem('fercayo_codigos',JSON.stringify(obj));
  loadCodigosSuggestions();
}
function handleMedidorChange(v){ document.getElementById('medidor-outro-wrap').style.display=v==='outro'?'':'none'; }
function handleDiretorChange(v){ document.getElementById('diretor-outro-wrap').style.display=v==='outro'?'':'none'; }
function getMedidor(){ const s=document.getElementById('medidor-select').value; return s==='outro'?(document.getElementById('medidor-outro').value||'—'):s; }
function getDiretor(){ const s=document.getElementById('diretor-select').value; return s==='outro'?(document.getElementById('diretor-outro').value||'—'):s; }
function selectOption(el){ const g=el.dataset.group; document.querySelectorAll(`[data-group="${g}"]`).forEach(b=>b.classList.remove('selected')); el.classList.add('selected'); selections[g]=el.dataset.val; }

function addFoto(){
  fotoCount++; const id=fotoCount;
  fotos.push({id,ref:'',ambiente:'',desc:'',notas:'',imgData:null});
  const item=document.createElement('div'); item.className='foto-item'; item.id=`foto-item-${id}`;
  item.innerHTML=`<div class="foto-item-header"><span class="foto-item-num">Fotografia ${String(fotos.length).padStart(2,'0')}</span><button class="foto-item-remove" onclick="removeFoto(${id})">✕</button></div><div class="foto-item-body"><div class="field-row" style="margin-bottom:10px"><div class="field" style="margin:0"><label>Referência</label><input type="text" placeholder="231_coz_01" oninput="updateFoto(${id},'ref',this.value)"></div><div class="field" style="margin:0"><label>Ambiente</label><input type="text" placeholder="Cozinha..." oninput="updateFoto(${id},'ambiente',this.value)"></div></div><div class="field" style="margin-bottom:10px"><label>Descrição / Elemento</label><input type="text" placeholder="O que a foto mostra..." oninput="updateFoto(${id},'desc',this.value)"></div><div class="photo-upload" id="upload-${id}" onclick="triggerUpload(${id})"><input type="file" id="file-${id}" accept="image/*" onchange="handlePhoto(${id},this)"><div class="upload-icon">📷</div><div class="upload-text">Selecionar ou tirar fotografia</div><div class="upload-sub">Câmara ou galeria</div><img class="photo-preview" id="preview-${id}"><button class="photo-remove" id="remove-${id}" onclick="removePhoto(event,${id})">✕</button></div><div class="field" style="margin-top:10px;margin-bottom:0"><label>Notas / Interferências</label><textarea placeholder="Observações, interferências..." rows="2" oninput="updateFoto(${id},'notas',this.value)"></textarea></div></div>`;
  document.getElementById('foto-list').appendChild(item);
  item.scrollIntoView({behavior:'smooth',block:'nearest'});
}
function removeFoto(id){ autoSave(); if(fotos.length<=1)return; fotos=fotos.filter(f=>f.id!==id); document.getElementById(`foto-item-${id}`).remove(); document.querySelectorAll('.foto-item-num').forEach((el,i)=>{el.textContent=`Fotografia ${String(i+1).padStart(2,'0')}`;});}
function updateFoto(id,field,val){ autoSave(); const f=fotos.find(f=>f.id===id); if(f)f[field]=val; }
function triggerUpload(id){ document.getElementById(`file-${id}`).click(); }
function handlePhoto(id,input){
  if(!input.files||!input.files[0])return;
  const reader=new FileReader();
  reader.onload=e=>{
    const data=e.target.result; const f=fotos.find(f=>f.id===id); if(f)f.imgData=data;
    const upload=document.getElementById(`upload-${id}`);
    document.getElementById(`preview-${id}`).src=data; document.getElementById(`preview-${id}`).classList.add('visible');
    document.getElementById(`remove-${id}`).classList.add('visible'); upload.classList.add('has-photo');
    upload.querySelector('.upload-icon').style.display='none'; upload.querySelector('.upload-text').style.display='none'; upload.querySelector('.upload-sub').style.display='none';
  };
  reader.readAsDataURL(input.files[0]);
}
function removePhoto(e,id){
  e.stopPropagation(); const f=fotos.find(f=>f.id===id); if(f)f.imgData=null;
  const upload=document.getElementById(`upload-${id}`);
  document.getElementById(`preview-${id}`).src=''; document.getElementById(`preview-${id}`).classList.remove('visible');
  document.getElementById(`remove-${id}`).classList.remove('visible'); upload.classList.remove('has-photo');
  upload.querySelector('.upload-icon').style.display=''; upload.querySelector('.upload-text').style.display=''; upload.querySelector('.upload-sub').style.display='';
  document.getElementById(`file-${id}`).value='';
}

function buildSummary(){
  const vals={'Código da Obra':document.getElementById('cod-obra').value||'—','Morada':document.getElementById('morada').value||'—','Cliente':document.getElementById('cliente').value||'—','Medidor':getMedidor(),'Data':document.getElementById('data-lev').value||'—','Diretor de Obra':getDiretor(),'Revisão':document.getElementById('revisao').value||'—','Tipo':selections['tipo']||'—','Fase':selections['fase']||'—'};
  document.getElementById('summary-content').innerHTML=`<div class="summary-block"><div class="summary-head">Identificação <span class="summary-edit" onclick="goToStep(0)">Editar</span></div><div class="summary-body">${Object.entries(vals).map(([k,v])=>`<div class="summary-row"><span class="s-label">${escHtml(k)}</span><span class="s-val">${escHtml(v)}</span></div>`).join('')}</div></div><div class="summary-block"><div class="summary-head">Acesso <span class="summary-edit" onclick="goToStep(1)">Editar</span></div><div class="summary-body"><div class="summary-row"><span class="s-label">Encarregado</span><span class="s-val">${document.getElementById('encarregado').value||'—'}</span></div><div class="summary-row"><span class="s-label">Horário</span><span class="s-val">${document.getElementById('horario').value||'—'}</span></div></div></div><div class="summary-block"><div class="summary-head">Fotografias — ${fotos.length} registo(s) <span class="summary-edit" onclick="goToStep(2)">Editar</span></div><div class="summary-body">${fotos.map((f,i)=>`<div class="summary-row"><span class="s-label">${f.ref||`Foto ${i+1}`}</span><span class="s-val">${f.ambiente||'—'} ${f.imgData?'📷':'⚠ Sem foto'}</span></div>`).join('')}</div></div>`;
}

async function generateDocument(){ buildSummary(); currentStep=totalSteps; document.querySelectorAll('.section').forEach(s=>s.classList.remove('active')); document.getElementById('section-4').classList.add('active'); updateNav(); window.scrollTo(0,0); saveCodigoSuggestion(document.getElementById('cod-obra').value); }
function backToEdit(){ goToStep(3); }


const DB_NAME = 'FercayoDB', DB_VER = 1;
let db = null;

function abrirDB(){
  return new Promise((res, rej) => {
    const req = indexedDB.open(DB_NAME, DB_VER);
    req.onupgradeneeded = e => {
      const d = e.target.result;
      if(!d.objectStoreNames.contains('rascunho')) d.createObjectStore('rascunho');
      if(!d.objectStoreNames.contains('fotos'))    d.createObjectStore('fotos', {keyPath:'id'});
    };
    req.onsuccess = e => { db = e.target.result; res(db); };
    req.onerror   = e => rej(e);
  });
}

function dbPut(store, key, val){
  return new Promise((res, rej) => {
    const tx = db.transaction(store, 'readwrite');
    const s  = tx.objectStore(store);
    const r  = store === 'fotos' ? s.put(val) : s.put(val, key);
    r.onsuccess = () => res();
    r.onerror   = e  => rej(e);
  });
}

function dbGet(store, key){
  return new Promise((res, rej) => {
    const tx = db.transaction(store, 'readonly');
    const r  = tx.objectStore(store).get(key);
    r.onsuccess = e => res(e.target.result);
    r.onerror   = e => rej(e);
  });
}

function dbGetAll(store){
  return new Promise((res, rej) => {
    const tx = db.transaction(store, 'readonly');
    const r  = tx.objectStore(store).getAll();
    r.onsuccess = e => res(e.target.result);
    r.onerror   = e => rej(e);
  });
}

function dbClear(store){
  return new Promise((res, rej) => {
    const tx = db.transaction(store, 'readwrite');
    const r  = tx.objectStore(store).clear();
    r.onsuccess = () => res();
    r.onerror   = e  => rej(e);
  });
}

async function limparRascunho(){
  if(!db) return;
  await dbClear('rascunho');
  await dbClear('fotos');
}

function recolherCampos(){
  const ids = [
    'cod-obra','morada','cliente','data-lev','revisao',
    'medidor-select','medidor-outro',
    'diretor-select','diretor-outro',
    'encarregado','contacto','horario',
    'obs-acesso','obs-gerais'
  ];
  const campos = {};
  ids.forEach(id => {
    const el = document.getElementById(id);
    if(el) campos[id] = el.value;
  });
  campos['_selections'] = JSON.stringify(selections);
  campos['_currentStep'] = currentStep;
  return campos;
}

let _saveTimer = null;
async function autoSave(){
  if(!db) return;
  clearTimeout(_saveTimer);
  _saveTimer = setTimeout(async () => {
    try {
      const campos = recolherCampos();
      await dbPut('rascunho', 'campos', campos);
      // guardar fotos
      await dbClear('fotos');
      for(const f of fotos){
        await dbPut('fotos', null, f);
      }
    } catch(e){ console.warn('AutoSave erro:', e); }
  }, 800);
}

async function verificarRascunho(){
  try {
    await abrirDB();
    const campos = await dbGet('rascunho', 'campos');
    if(!campos) return;
    const cod  = campos['cod-obra']  || '—';
    const data = campos['data-lev']  || '—';
    if(cod === '—' && data === '—') return; // rascunho vazio
    document.getElementById('rb-cod').textContent  = cod;
    document.getElementById('rb-data').textContent = data;
    document.getElementById('rascunho-banner').style.display = 'flex';
  } catch(e){ console.warn('verificarRascunho erro:', e); }
}

async function recuperarRascunho(){
  document.getElementById('rascunho-banner').style.display = 'none';
  try {
    const campos = await dbGet('rascunho', 'campos');
    if(!campos) return;

    // preencher campos
    const ids = [
      'cod-obra','morada','cliente','data-lev','revisao',
      'medidor-select','medidor-outro',
      'diretor-select','diretor-outro',
      'encarregado','contacto','horario',
      'obs-acesso','obs-gerais'
    ];
    ids.forEach(id => {
      const el = document.getElementById(id);
      if(el && campos[id] !== undefined) el.value = campos[id];
    });

    // restaurar selects especiais
    if(campos['medidor-select']){
      handleMedidorChange(campos['medidor-select']);
    }
    if(campos['diretor-select']){
      handleDiretorChange(campos['diretor-select']);
    }

    // restaurar selections (tipo, fase, etc)
    if(campos['_selections']){
      try {
        const sel = JSON.parse(campos['_selections']);
        Object.assign(selections, sel);
        // reflectir botões de opção
        document.querySelectorAll('.option-btn').forEach(btn => {
          const grp = btn.dataset.group, val = btn.dataset.value;
          if(grp && selections[grp] === val) btn.classList.add('selected');
          else btn.classList.remove('selected');
        });
      } catch(e){}
    }

    // restaurar fotos
    const fotosGuardadas = await dbGetAll('fotos');
    if(fotosGuardadas && fotosGuardadas.length > 0){
      fotos.length = 0;
      fotosGuardadas.forEach(f => fotos.push(f));
      renderFotos();
    }

    // ir para o passo onde estava
    const step = parseInt(campos['_currentStep']) || 0;
    if(step > 0){
      currentStep = 0; // reset para navegação funcionar
      goToStep(step);
    }

    // repopular sugestões de código
    saveCodigoSuggestion(campos['cod-obra'] || '');

  } catch(e){ console.warn('recuperarRascunho erro:', e); }
}

async function descartarRascunho(){
  document.getElementById('rascunho-banner').style.display = 'none';
  await limparRascunho();
}

function renderFotos(){
  const lista = document.getElementById('foto-list');
  lista.innerHTML = '';
  fotos.forEach(f => {
    const item = document.createElement('div');
    item.className = 'foto-item';
    item.id = `foto-item-${f.id}`;
    item.innerHTML = `<div class="foto-item-header"><span class="foto-item-num">Fotografia ${String(fotos.indexOf(f)+1).padStart(2,'0')}</span><button class="foto-item-remove" onclick="removeFoto(${f.id})">✕</button></div><div class="foto-item-body"><div class="field-row" style="margin-bottom:10px"><div class="field" style="flex:1"><label>Referência</label><input type="text" id="ref-${f.id}" value="${escHtml(f.ref||'')}" oninput="updateFoto(${f.id},'ref',this.value)" placeholder="ex: 231_cozinha_01"></div><div class="field" style="flex:1"><label>Ambiente</label><input type="text" id="amb-${f.id}" value="${escHtml(f.ambiente||'')}" oninput="updateFoto(${f.id},'ambiente',this.value)" placeholder="ex: Cozinha"></div></div><div class="field"><label>Descrição / Elemento</label><input type="text" id="desc-${f.id}" value="${escHtml(f.desc||'')}" oninput="updateFoto(${f.id},'desc',this.value)" placeholder="ex: Parede lateral com tomada"></div><div class="field" style="margin-top:6px"><label>Notas</label><textarea id="notas-${f.id}" oninput="updateFoto(${f.id},'notas',this.value)" placeholder="Observações sobre esta fotografia..." style="min-height:56px">${escHtml(f.notas||'')}</textarea></div>${f.imgData ? `<div class="foto-preview-wrap" style="position:relative;margin-top:8px"><img src="${f.imgData}" class="photo-preview" style="display:block"><button class="photo-remove" style="display:flex" onclick="removeImg(${f.id})">✕</button></div>` : `<button class="add-foto-btn" onclick="triggerCamera(${f.id})">📷 Adicionar Fotografia</button><input type="file" id="file-${f.id}" accept="image/*" capture="environment" style="display:none" onchange="handleFile(${f.id},this)">`}</div>`;
    lista.appendChild(item);
  });
}

async function downloadPDF(){
  const {jsPDF}=window.jspdf;
  const doc=new jsPDF({orientation:'p',unit:'mm',format:'a4'});
  const W=210, H=297;
  // ── PALETA IMPRESSÃO — fundo branco, acentos leves ──
  const WHITE=[255,255,255];
  const CER=[175,124,52];       // Castanho Cerejeira
  const DARK=[51,62,72];        // Cinzento Escuro — só texto e linhas finas
  const MID=[106,112,121];      // Cinzento Intermédio
  const LIGHT=[164,169,173];    // Cinzento Claro
  const PANEL=[242,240,237];    // Fundo muito claro para campos
  const LINE=[216,212,204];     // Linhas separadoras

  // Margens oficiais Fercayo
  const ML=15, MR=15, MT=20, MB=8;
  const CW=W-ML-MR; // content width = 180mm

  const sf=(r,g,b)=>doc.setFillColor(r,g,b);
  const ss=(r,g,b,lw=0.3)=>{doc.setDrawColor(r,g,b);doc.setLineWidth(lw);};
  const st=(r,g,b)=>doc.setTextColor(r,g,b);

  // ── LOGO COMPLETO ──
  async function drawLogo(yy){
    return new Promise(resolve=>{
      const tmp=new Image();
      tmp.onload=()=>{
        // logo ratio: 1455x364 → fit in ~60mm wide, ~15mm tall
        const lw=62, lh=lw*(364/1455);
        doc.addImage(LOGO_B64,'PNG',ML,yy,lw,lh);
        resolve(lh);
      };
      tmp.onerror=()=>{ st(...DARK); doc.setFont('helvetica','bold'); doc.setFontSize(11); doc.text('FERCAYO CARPINTARIAS',ML,yy+8); resolve(10); };
      tmp.src=LOGO_B64;
    });
  }

  // ── RODAPÉ OFICIAL ──
  function drawFooter(){
    const fy=H-12;
    // linha separadora cerejeira
    ss(...CER,0.5); doc.line(ML,fy-2,W-MR,fy-2);
    doc.setFont('helvetica','normal'); doc.setFontSize(7); st(...MID);
    const info='geral@fercayo.pt   |   (+351) 252 601 189   |   Rua Manuel José Moreira, nº835, 4570-366 Laundos, Póvoa de Varzim   |   FERCAYO.PT';
    doc.text(info,W/2,fy+2,{align:'center'});
  }

  // ── CABEÇALHO DE PÁGINA ──
  async function drawPageHeader(pageLabel,extra=''){
    sf(...WHITE); doc.rect(0,0,W,H,'F');
    const lh = await drawLogo(4);
    // linha cerejeira sob logo
    ss(...CER,0.6); doc.line(ML,MT-1,W-MR,MT-1);
    // label da página à direita
    st(...MID); doc.setFont('helvetica','normal'); doc.setFontSize(7.5);
    doc.text(pageLabel,W-MR,MT-3,{align:'right'});
    if(extra){ doc.text(extra,W-MR,MT+1.5,{align:'right'}); }
    drawFooter();
    return MT+4; // return starting y
  }

  function drawFieldPDF(label,value,x,w,yy){
    st(...LIGHT); doc.setFont('helvetica','bold'); doc.setFontSize(6.5);
    doc.text(label.toUpperCase(),x,yy);
    st(...DARK); doc.setFont('helvetica','normal'); doc.setFontSize(10);
    doc.text(String(value||'—'),x,yy+5);
    ss(...LINE,0.25); doc.line(x,yy+7,x+w,yy+7);
  }

  function sectionHeader(label,x,w,yy){
    ss(...CER,0.4); doc.line(x,yy,x+w,yy);
    st(...CER); doc.setFont('helvetica','bold'); doc.setFontSize(7.5);
    doc.text(label.toUpperCase(),x,yy-1.5);
    return yy+4;
  }

  function tagBox(label,x,yy){
    ss(...CER,0.5); doc.roundedRect(x,yy,50,7,1,1,'S');
    st(...CER); doc.setFont('helvetica','bold'); doc.setFontSize(9);
    doc.text(label,x+4,yy+5);
  }

  // ── PAGE 1: INFORMAÇÕES ──
  let y = await drawPageHeader('Ficha de Levantamento em Obra');
  y += 2;

  // Título da secção
  st(...DARK); doc.setFont('helvetica','bold'); doc.setFontSize(14);
  doc.text('INFORMAÇÕES DA OBRA',ML,y); y+=2;
  sf(...CER); doc.rect(ML,y,20,1,'F'); y+=6;

  drawFieldPDF('Código da Obra',document.getElementById('cod-obra').value,ML,CW,y); y+=14;
  drawFieldPDF('Morada / Local da Obra',document.getElementById('morada').value,ML,CW,y); y+=14;
  drawFieldPDF('Cliente',document.getElementById('cliente').value,ML,CW,y); y+=16;
  drawFieldPDF('Medidor',getMedidor(),ML,CW/2-4,y);
  drawFieldPDF('Data',document.getElementById('data-lev').value,ML+CW/2+4,CW/2-4,y); y+=14;
  drawFieldPDF('Diretor de Obra',getDiretor(),ML,CW/2-4,y);
  drawFieldPDF('Código de Revisão',document.getElementById('revisao').value,ML+CW/2+4,CW/2-4,y); y+=18;

  y = sectionHeader('Tipo de Intervenção e Fase',ML,CW,y); y+=4;
  tagBox(selections['tipo']||'—',ML,y);
  tagBox(selections['fase']||'—',ML+58,y); y+=16;

  y = sectionHeader('Acesso à Obra',ML,CW,y); y+=4;
  drawFieldPDF('Encarregado de Obra',document.getElementById('encarregado').value,ML,CW/2-4,y);
  drawFieldPDF('Contacto',document.getElementById('contacto').value,ML+CW/2+4,CW/2-4,y); y+=14;
  drawFieldPDF('Horário de Acesso',document.getElementById('horario').value,ML,CW,y); y+=14;

  const obsA=document.getElementById('obs-acesso').value;
  if(obsA){
    st(...LIGHT); doc.setFont('helvetica','bold'); doc.setFontSize(6.5);
    doc.text('OBSERVAÇÕES DE ACESSO',ML,y); y+=5;
    st(...DARK); doc.setFont('helvetica','normal'); doc.setFontSize(9);
    y = await writeWrapped(doc,obsA,ML,CW,y,5,drawPageHeader,'Identificação e Acesso',''); y+=8;
  }
  const obsG=document.getElementById('obs-gerais').value;
  if(obsG){
    y = sectionHeader('Observações Gerais',ML,CW,y); y+=4;
    st(...DARK); doc.setFont('helvetica','normal'); doc.setFontSize(9);
    y = await writeWrapped(doc,obsG,ML,CW,y,5,drawPageHeader,'Identificação e Acesso',''); y+=3;
  }
  // page num
  st(...LIGHT); doc.setFont('helvetica','normal'); doc.setFontSize(7);
  doc.text('01',W-MR,H-MB,{align:'right'});

  // ── FOTO PAGES ──
  for(let i=0;i<fotos.length;i++){
    const f=fotos[i];
    doc.addPage();
    const extra=`Foto ${String(i+1).padStart(2,'0')} / ${String(fotos.length).padStart(2,'0')}  ·  ${document.getElementById('cod-obra').value||'—'}`;
    let py = await drawPageHeader('Registo Fotográfico',extra);
    py+=2;

    const half=CW/2-3;
    drawFieldPDF('Referência',f.ref,ML,half,py);
    drawFieldPDF('Ambiente',f.ambiente,ML+half+6,half,py); py+=16;
    drawFieldPDF('Descrição / Elemento',f.desc,ML,CW,py); py+=16;

    if(f.imgData){
      await new Promise(resolve=>{
        const tmp=new Image();
        tmp.onload=()=>{
          const mW=CW, mH=H-py-28;
          const r=Math.min(mW/tmp.naturalWidth,mH/tmp.naturalHeight);
          const dw=tmp.naturalWidth*r, dh=tmp.naturalHeight*r;
          const dx=ML+(mW-dw)/2;
          // light border around photo
          ss(...LINE,0.3); doc.rect(dx-1,py-1,dw+2,dh+2,'S');
          doc.addImage(f.imgData,'JPEG',dx,py,dw,dh);
          py+=dh+6; resolve();
        };
        tmp.onerror=resolve; tmp.src=f.imgData;
      });
    } else {
      ss(...LINE,0.4); doc.rect(ML,py,CW,60,'S');
      st(...LIGHT); doc.setFont('helvetica','italic'); doc.setFontSize(10);
      doc.text('[Sem fotografia]',W/2,py+32,{align:'center'}); py+=66;
    }

    if(f.notas){
      py = sectionHeader('Notas e Observações',ML,CW,py); py+=4;
      st(...DARK); doc.setFont('helvetica','normal'); doc.setFontSize(9);
      py = await writeWrapped(doc,f.notas,ML,CW,py,5,drawPageHeader,'Registo Fotográfico',`Foto ${String(i+1).padStart(2,'0')} / ${String(fotos.length).padStart(2,'0')}  ·  ${document.getElementById('cod-obra').value||'—'}`); 
    }

    // page number — get current page after possible overflow
    const curPage = doc.internal.getCurrentPageInfo().pageNumber;
    doc.setPage(curPage);
    st(...LIGHT); doc.setFont('helvetica','normal'); doc.setFontSize(7);
    doc.text(String(i+2).padStart(2,'0'),W-MR,H-MB,{align:'right'});
  }

  const cod=(document.getElementById('cod-obra').value||'obra').replace(/\s+/g,'_');
  const dir=getDiretor().replace(/\s+/g,'_').replace(/[^a-zA-Z\u00C0-\u00FF0-9_]/g,'');
  const dt=(document.getElementById('data-lev').value||'data').replace(/-/g,'');
  doc.save(`${cod}-${dir}-${dt}.pdf`);
  await limparRascunho();
}


async function writeWrapped(doc, txt, x, maxW, y, lineH, drawHeaderFn, headerLabel, headerExtra){
  const MB_SAFE = 22; // margem de segurança acima do rodapé
  const H = doc.internal.pageSize.getHeight();
  const lines = doc.splitTextToSize(txt, maxW);
  for(let i=0; i<lines.length; i++){
    if(y + lineH > H - MB_SAFE){
      doc.addPage();
      y = await drawHeaderFn(headerLabel, headerExtra);
      y += 4;
    }
    doc.text(lines[i], x, y);
    y += lineH;
  }
  return y;
}

function shareWhatsApp(){
  const obra=document.getElementById('cod-obra').value||'obra';
  const texto=`Levantamento em obra — ${obra}\nMedidor: ${getMedidor()}\nData: ${document.getElementById('data-lev').value||''}\n\nFercayo Carpintarias`;
  window.open(`https://wa.me/?text=${encodeURIComponent(texto)}`);
}

document.addEventListener('input',  () => autoSave());
document.addEventListener('change', () => autoSave());

function resetApp(){ limparRascunho().then(()=>location.reload()); }
